const FAQ_ITEMS = [
  {cat:'Primeiros pasos', q:'Non sei que estudar. Por onde empezo?', a:'Comeza por dúas decisións pequenas: que che gustaría facer no día a día e que condicións precisas, por exemplo tempo, desprazamento, modalidade, nota ou empregabilidade. Despois utiliza o buscador para comparar estudos por familia e abre dúas ou tres fichas antes de decidir.', links:['https://www.edu.xunta.gal/fp/oferta-fp','https://siiu.universidades.gob.es/QEDU/']},
  {cat:'ESO', q:'Que opcións hai ao rematar ESO co título?', a:'Co título de ESO podes continuar por Bacharelato, acceder a FP de grao medio, cursar ensinanzas artísticas ou deportivas segundo requisitos, ou incorporarte a outras formacións. A decisión debe depender da meta, non só da comodidade inmediata.', links:['https://educagob.educacionfpydeportes.gob.es/ensenanzas/secundaria/informacion-general/opciones-al-terminar.html']},
  {cat:'ESO', q:'E se non teño o título de ESO?', a:'Cómpre valorar educación de persoas adultas, probas para obter o título cando proceda, ciclos de grao básico se se cumpren requisitos de idade e proposta educativa, probas de acceso ou certificados profesionais segundo perfil. Non convén elixir unha vía sen revisar requisitos oficiais.', links:['https://educagob.educacionfpydeportes.gob.es/ensenanzas/secundaria/informacion-general/opciones-al-terminar.html','https://www.todofp.es/inicio.html']},
  {cat:'Bacharelato', q:'Que Bacharelato escoller se quero universidade?', a:'Depende do grao. Para saúde e enxeñarías adoita ser máis coherente Ciencias e Tecnoloxía; para dereito, ADE, educación ou criminoloxía adoita encaixar Humanidades e Ciencias Sociais; para belas artes, deseño ou música pode encaixar Artes. Deben revisarse as ponderacións da CIUG e a nota necesaria.', links:['https://ciug.gal/gal/ponderacions','https://siiu.universidades.gob.es/QEDU/']},
  {cat:'FP', q:'Como se accede a FP de grao medio?', a:'A vía ordinaria é ter o título de ESO ou equivalente. Tamén poden existir outras vías por probas, cursos preparatorios ou certificados segundo normativa. O criterio concreto debe verificarse en TodoFP e na convocatoria autonómica.', links:['https://www.todofp.es/como-cuando-y-donde-estudiar/acceso-fp-desde-fp/como-accedo-a-fp.html','https://www.edu.xunta.gal/fp/admision-grao-medio']},
  {cat:'FP', q:'Como se accede a FP de grao superior?', a:'Pódese acceder con Bacharelato, cun título de Técnico de FP, con outros títulos ou mediante proba/curso de acceso cando proceda. Se xa tes grao medio, grao superior pode ser unha continuidade moi práctica.', links:['https://www.todofp.es/como-cuando-y-donde-estudiar/acceso-fp-desde-fp/como-accedo-a-fp.html','https://www.edu.xunta.gal/fp/admision-grao-superior']},
  {cat:'FP', q:'Que é a formación acelerada?', a:'É unha oferta intensiva ligada a necesidades formativas concretas. Pode ser útil para persoas adultas ou para cambio profesional, pero depende de convocatoria, prazas, centros e requisitos. Hai que revisar cada edición.', links:['https://www.edu.xunta.gal/fp/formacion-acelerada']},
  {cat:'Certificados', q:'Que son os certificados profesionais?', a:'Son acreditacións oficiais vinculadas ao ámbito laboral. Poden ser unha vía moi interesante para mellorar empregabilidade, acreditar competencias ou cambiar de sector sen iniciar necesariamente un ciclo completo.', links:['https://www.sepe.es/HomeSepe/formacion-trabajo/catalogo-especialidades-formativas.html']},
  {cat:'Universidade', q:'Onde comprobo se un grao ou máster é oficial?', a:'Para estudos universitarios debes revisar QEDU e o RUCT. QEDU axuda a comparar títulos, universidades e datos útiles; o RUCT é o rexistro oficial de universidades, centros e títulos.', links:['https://siiu.universidades.gob.es/QEDU/','https://www.educacionfpydeportes.gob.es/servicios-al-ciudadano/catalogo/general/99/997950/ficha/997950.html']},
  {cat:'Universidade', q:'Que diferenza hai entre grao e máster habilitante?', a:'Un grao é unha titulación universitaria básica. Un máster habilitante é necesario para exercer determinadas profesións reguladas, por exemplo profesorado de secundaria, avogacía ou algunhas enxeñarías/arquitectura segundo o caso.', links:['https://www.educacionfpydeportes.gob.es/servicios-al-ciudadano/catalogo/general/99/997950/ficha/997950.html']},
  {cat:'Universidade', q:'Psicoloxía permite traballar en clínica directamente?', a:'Non abonda con rematar o grao para exercer como Psicólogo/a Xeral Sanitario/a. Normalmente é preciso o Máster en Psicoloxía Xeral Sanitaria. Para especialista en Psicoloxía Clínica a vía é PIR.', links:['https://www.educacionfpydeportes.gob.es/servicios-al-ciudadano/catalogo/general/99/997950/ficha/997950.html']},
  {cat:'Universidade', q:'Para ser profesor/a de secundaria que necesito?', a:'Normalmente necesitas unha titulación universitaria que permita acceder á especialidade correspondente, o Máster Universitario en Profesorado de Educación Secundaria e superar o proceso selectivo se queres ensino público.', links:['https://www.educacionfpydeportes.gob.es/servicios-al-ciudadano/catalogo/general/99/997950/ficha/997950.html']},
  {cat:'Admisión', q:'Que son as ponderacións da ABAU/PAU?', a:'Son valores que multiplican materias concretas para mellorar a nota de admisión a un grao universitario. Se unha materia pondera máis para a túa carreira, pode ser estratéxica. Deben revisarse na CIUG para o curso correspondente.', links:['https://ciug.gal/gal/ponderacions']},
  {cat:'Admisión', q:'Que son as notas de corte?', a:'Son a nota da última persoa admitida nun grao e convocatoria concreta. Non son unha nota fixa de acceso, cambian cada ano segundo demanda e prazas. Serven como orientación, non como garantía.', links:['https://ciug.gal/gal/notas-corte','https://siiu.universidades.gob.es/QEDU/']},
  {cat:'Becas', q:'Onde se solicitan as becas de estudos?', a:'As becas xerais do Ministerio e outras axudas teñen convocatorias, prazos e requisitos propios. Deben consultarse na sede oficial e non convén esperar ao último día.', links:['https://www.becaseducacion.gob.es/portada.html']},
  {cat:'Necesidades educativas', q:'Hai axudas para alumnado con necesidades específicas de apoio educativo?', a:'Si, existe unha convocatoria específica do Ministerio para alumnado con necesidade específica de apoio educativo. É imprescindible revisar prazo, requisitos, documentación e procedemento da convocatoria vixente.', links:['https://www.educacionfpydeportes.gob.es/servicios-al-ciudadano/catalogo/general/05/050140/ficha/050140.html']},
  {cat:'Adultos', q:'Son persoa adulta e quero volver estudar. Teño que empezar desde cero?', a:'Non necesariamente. Hai que revisar que titulación tes, experiencia laboral, idade, tempo dispoñible e obxectivo. Pode encaixar ESO de adultos, Bacharelato de adultos, FP, certificados profesionais, acreditación de competencias ou universidade.', links:['https://www.edu.xunta.gal/fp','https://www.sepe.es/HomeSepe/formacion-trabajo/catalogo-especialidades-formativas.html']},
  {cat:'Cambio profesional', q:'Quero cambiar de profesión. Que vía adoita ser máis rápida?', a:'Depende do punto de partida. Se buscas incorporación laboral rápida, certificados profesionais, formación acelerada ou FP poden ser máis directos. Se a profesión é regulada ou require título universitario, a vía será máis longa.', links:['https://www.edu.xunta.gal/fp/formacion-acelerada','https://www.sepe.es/HomeSepe/formacion-trabajo/catalogo-especialidades-formativas.html','https://siiu.universidades.gob.es/QEDU/']},
  {cat:'Recoñecemento', q:'Podo validar ou recoñecer estudos previos?', a:'Pode existir validación, convalidación ou recoñecemento segundo tipo de ensino. En FP, universidade e certificados os procedementos son distintos. Non se debe dar por feito ata revisar normativa e solicitalo formalmente.', links:['https://www.todofp.es/inicio.html','https://www.educacionfpydeportes.gob.es/servicios-al-ciudadano/catalogo/general/99/997950/ficha/997950.html']},
  {cat:'Centros', q:'Onde podo ver en que centros se imparte un ciclo de FP en Galicia?', a:'Na web de FP da Xunta podes consultar oferta por familia, ciclo, provincia, concello, réxime e centro. A oferta cambia por curso, polo que hai que revisar a convocatoria actual.', links:['https://www.edu.xunta.gal/fp/oferta-fp','https://www.edu.xunta.gal/fp/centros']}
];
