    add(`Cursar ${st.name}`, 'O ciclo de grao superior prepara para perfís técnicos cualificados e tamén permite continuidade a universidade ou cursos de especialización.', st.subjects || [], ['https://www.edu.xunta.gal/fp/ciclos']);
    add('Saír ao emprego, especializarte ou acceder á universidade', 'Ao rematar podes traballar, cursar especialización FP ou solicitar graos universitarios relacionados.', (st.career_outputs||[]).slice(0,8), ['https://siiu.universidades.gob.es/QEDU/']);
