    if(start === 'fp-higher') add('Acceder á universidade desde FP superior', 'Un título de Técnico Superior permite acceso á universidade. Se necesitas subir nota, revisa materias da fase voluntaria da ABAU/PAU que ponderen para este grao.', bach.subjects, ['https://ciug.gal/gal/ponderacions']);
    if(['bach','degree','career-change'].includes(start)) add('Preparar admisión universitaria', 'Comproba nota de corte, prazas, ponderacións, campus, modalidade e prazos. Se xa tes grao, revisa admisión para titulados/as e posibles recoñecementos.', ['QEDU permite comparar onde se imparte o grao.', 'RUCT permite comprobar oficialidade.'], ['https://siiu.universidades.gob.es/QEDU/','https://ciug.gal/gal/notas-corte']);
